<style>
/* ---- About Page Scoped Variables ---- */
.about-page-html {
    --font-display: "Outfit", "Trebuchet MS", sans-serif;
    --font-body: "DM Sans", "Segoe UI", sans-serif;
    --color-primary: #0B8A8D;
    --color-primary-dark: #076E70;
    --color-primary-light: #E0F5F5;
    --color-secondary: #F5A623;
    --color-secondary-dark: #D4891A;
    --color-secondary-light: #FFF3DC;
    --color-accent: #E8554E;
    --color-accent-light: #FDEAE9;
    --color-dark: #1B2A4A;
    --color-dark-soft: #2D3E5F;
    --color-text: #3A4A6B;
    --color-text-light: #7A8BB5;
    --color-border: #E2E8F0;
    --color-bg: #FAFCFF;
    --color-bg-warm: #FFFAF3;
    --color-bg-teal: #F0FAFA;
    --color-white: #ffffff;
    --radius-sm: 8px;
    --radius-md: 14px;
    --radius-lg: 22px;
    --radius-xl: 30px;
    --radius-full: 9999px;
    --shadow-sm: 0 2px 8px rgba(11,138,141,0.06);
    --shadow-md: 0 4px 24px rgba(11,138,141,0.1);
    --shadow-lg: 0 10px 40px rgba(11,138,141,0.12);
    --ease-out: cubic-bezier(0.16,1,0.3,1);
    font-family: var(--font-body);
    color: var(--color-text);
    line-height: 1.7;
}
.about-page-html *, .about-page-html *::before, .about-page-html *::after { box-sizing: border-box; margin: 0; padding: 0; }
.about-page-html img { max-width: 100%; height: auto; display: block; }
.about-page-html h1,.about-page-html h2,.about-page-html h3,.about-page-html h4 {
    font-family: var(--font-display); color: var(--color-dark); line-height: 1.2; font-weight: 700; margin: 0 0 0.6rem; letter-spacing: -0.01em;
}
.about-page-html p { margin: 0 0 1rem; }
.about-page-html a { color: var(--color-primary); text-decoration: none; transition: color 0.3s var(--ease-out); }
.about-page-html a:hover { color: var(--color-primary-dark); }

/* Container */
.about-page-html .container { max-width: 1180px; margin: auto; padding: 0 1.5rem; }

/* Section */
.about-page-html .section { padding: 5rem 0; }
.about-page-html .section-header { text-align: center; margin-bottom: 3rem; }
.about-page-html .section-header h2 {
    font-size: clamp(1.8rem,3.5vw,2.8rem); font-weight: 800;
    background: linear-gradient(135deg, var(--color-dark) 0%, var(--color-primary-dark) 100%);
    -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
    margin-bottom: 0.75rem;
}
.about-page-html .section-header p { font-size: 1.05rem; color: var(--color-text-light); max-width: 580px; margin: 0 auto; line-height: 1.7; }

/* Eyebrow */
.about-page-html .eyebrow {
    display: inline-flex; align-items: center; gap: 0.5rem;
    font-family: var(--font-display); font-size: 0.75rem; font-weight: 700;
    letter-spacing: 0.18em; text-transform: uppercase; color: var(--color-primary);
    background: var(--color-primary-light); padding: 0.35rem 1rem; border-radius: var(--radius-full); margin-bottom: 0.75rem;
}
.about-page-html .eyebrow svg { width: 15px; height: 15px; stroke: var(--color-primary); flex-shrink: 0; stroke-width: 2.2; }

/* Global SVG Icon Sizing */
.about-page-html .about-highlight-icon svg,
.about-page-html .about-mv-icon svg { width: 22px; height: 22px; stroke-width: 2; flex-shrink: 0; }
.about-page-html .about-highlight-icon svg { stroke: var(--color-primary); }
.about-page-html .about-mv-icon svg { stroke: var(--color-primary); }
.about-page-html .icon-amber svg { stroke: var(--color-secondary-dark); }
.about-page-html .icon-coral svg { stroke: var(--color-accent); }
.about-page-html .mv-vision .about-mv-icon svg { stroke: var(--color-secondary-dark); }

/* Buttons */
.about-page-html .button {
    display: inline-flex; align-items: center; gap: 0.5rem;
    font-family: var(--font-display); font-weight: 600; font-size: 0.95rem;
    padding: 0.75rem 1.6rem; border-radius: var(--radius-full);
    border: 2px solid transparent; cursor: pointer;
    transition: all 0.4s var(--ease-out); text-decoration: none; line-height: 1.3;
}
.about-page-html .button:hover { transform: translateY(-2px); }
.about-page-html .button-accent {
    background: linear-gradient(135deg, var(--color-secondary), var(--color-secondary-dark));
    color: var(--color-white); box-shadow: 0 4px 18px rgba(245,166,35,0.3);
}
.about-page-html .button-accent:hover { box-shadow: 0 6px 28px rgba(245,166,35,0.4); color: var(--color-white); }
.about-page-html .button-light { background: var(--color-white); color: var(--color-dark); }

/* ==================== ABOUT HERO ==================== */
.about-page-html .about-hero {
    position: relative; padding: 9rem 0 4.5rem; text-align: center; overflow: hidden;
    background: linear-gradient(160deg, var(--color-dark) 0%, #151D36 60%, var(--color-primary-dark) 100%);
    color: var(--color-white);
}
.about-page-html .about-hero-bg {
    position: absolute; inset: 0;
    background: radial-gradient(ellipse at 20% 0%, rgba(11,138,141,0.2) 0%, transparent 60%),
                radial-gradient(ellipse at 80% 100%, rgba(245,166,35,0.1) 0%, transparent 50%);
    pointer-events: none;
}
.about-page-html .about-hero-bg::before {
    content: ""; position: absolute; top: -40%; right: -10%; width: 500px; height: 500px;
    border-radius: 50%; border: 1px solid rgba(255,255,255,0.04); pointer-events: none;
}
.about-page-html .about-hero-bg::after {
    content: ""; position: absolute; bottom: -30%; left: -5%; width: 400px; height: 400px;
    border-radius: 50%; border: 1px solid rgba(255,255,255,0.03); pointer-events: none;
}
.about-page-html .about-hero-inner { position: relative; z-index: 2; animation: about-hero-fade-up 0.9s var(--ease-out) both; }
.about-page-html .about-hero .eyebrow { background: rgba(11,138,141,0.2); color: rgba(255,255,255,0.9); }
.about-page-html .about-hero .eyebrow svg { stroke: rgba(255,255,255,0.9); }
.about-page-html .about-hero-title {
    font-size: clamp(2.2rem,5vw,3.6rem); font-weight: 800; line-height: 1.1;
    margin-bottom: 1.2rem; color: var(--color-white);
}
.about-page-html .about-hero-title .highlight { position: relative; color: var(--color-secondary); display: inline; }
.about-page-html .about-hero-title .highlight::after {
    content: ""; position: absolute; bottom: 2px; left: 0; right: 0; height: 6px;
    background: rgba(245,166,35,0.25); border-radius: 3px; z-index: -1;
}
.about-page-html .about-hero-lead { font-size: 1.1rem; color: rgba(255,255,255,0.7); max-width: 640px; margin: 0 auto 2.5rem; line-height: 1.8; }
.about-page-html .about-hero-shape { position: absolute; bottom: -1px; left: 0; right: 0; height: 60px; background: var(--color-white); clip-path: ellipse(55% 100% at 50% 100%); z-index: 3; }

@keyframes about-hero-fade-up { from { opacity: 0; transform: translateY(22px); } to { opacity: 1; transform: translateY(0); } }

/* ==================== WHO WE ARE ==================== */
.about-page-html .about-who { background: var(--color-white); }
.about-page-html .about-who-grid { display: grid; grid-template-columns: 1fr 1.15fr; gap: 4rem; align-items: center; }
.about-page-html .about-who-image { position: relative; }

/* Visual Card (no-image fallback) */
.about-page-html .about-who-visual-card {
    background: linear-gradient(160deg, var(--color-dark) 0%, #1a2d52 50%, var(--color-primary-dark) 100%);
    border-radius: var(--radius-xl); padding: 2.2rem; height: 440px;
    display: flex; flex-direction: column; justify-content: space-between;
    box-shadow: var(--shadow-lg); position: relative; overflow: hidden;
}
.about-page-html .about-who-visual-card::before {
    content: ""; position: absolute; top: -60%; right: -30%; width: 350px; height: 350px;
    background: radial-gradient(circle, rgba(11,138,141,0.2) 0%, transparent 70%);
    border-radius: 50%; pointer-events: none;
}
.about-page-html .about-who-visual-card::after {
    content: ""; position: absolute; bottom: -40%; left: -20%; width: 280px; height: 280px;
    background: radial-gradient(circle, rgba(245,166,35,0.12) 0%, transparent 70%);
    border-radius: 50%; pointer-events: none;
}
.about-page-html .about-vc-header { display: flex; align-items: center; gap: 0.8rem; position: relative; z-index: 1; }
.about-page-html .about-vc-logo {
    width: 44px; height: 44px; border-radius: var(--radius-md);
    background: linear-gradient(135deg, var(--color-primary), var(--color-secondary));
    display: flex; align-items: center; justify-content: center;
    font-family: var(--font-display); font-size: 1.4rem; font-weight: 800; color: var(--color-white);
}
.about-page-html .about-vc-brand { font-family: var(--font-display); font-size: 1.1rem; font-weight: 700; color: var(--color-white); }
.about-page-html .about-vc-sub { font-size: 0.72rem; color: rgba(255,255,255,0.45); font-weight: 500; }
.about-page-html .about-vc-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; position: relative; z-index: 1; }
.about-page-html .about-vc-stat {
    background: rgba(255,255,255,0.07); backdrop-filter: blur(8px);
    border: 1px solid rgba(255,255,255,0.08); border-radius: var(--radius-md);
    padding: 1rem; text-align: center; transition: background 0.3s ease;
}
.about-page-html .about-vc-stat:hover { background: rgba(255,255,255,0.12); }
.about-page-html .about-vc-stat-icon { margin-bottom: 0.4rem; }
.about-page-html .about-vc-stat-icon svg { width: 22px; height: 22px; stroke: var(--color-secondary); stroke-width: 2; }
.about-page-html .about-vc-stat-num { font-family: var(--font-display); font-size: 1.4rem; font-weight: 800; color: var(--color-white); line-height: 1; margin-bottom: 0.15rem; }
.about-page-html .about-vc-stat-lbl { font-size: 0.68rem; color: rgba(255,255,255,0.5); font-weight: 500; letter-spacing: 0.02em; }
.about-page-html .about-vc-tagline {
    text-align: center; font-family: var(--font-display); font-size: 0.82rem; font-weight: 600;
    color: rgba(255,255,255,0.5); letter-spacing: 0.08em; text-transform: uppercase;
    position: relative; z-index: 1;
}

.about-page-html .about-who-accent-box {
    position: absolute; bottom: -18px; right: -18px;
    background: linear-gradient(135deg, var(--color-primary), var(--color-primary-dark));
    color: var(--color-white); padding: 1.2rem 1.5rem; border-radius: var(--radius-lg);
    box-shadow: var(--shadow-lg); text-align: center; z-index: 2;
}
.about-page-html .about-who-accent-num { font-family: var(--font-display); font-size: 2.2rem; font-weight: 800; line-height: 1; }
.about-page-html .about-who-accent-txt { font-size: 0.72rem; opacity: 0.85; margin-top: 0.15rem; line-height: 1.3; }

.about-page-html .about-who-content h2 { font-size: clamp(1.6rem,3vw,2.2rem); margin-bottom: 1rem; }
.about-page-html .about-text-main { font-size: 1.02rem; color: var(--color-text-light); line-height: 1.85; margin-bottom: 1rem; }
.about-page-html .about-text-main strong { color: var(--color-dark); }

/* Highlights Grid */
.about-page-html .about-highlights { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-top: 1.5rem; }
.about-page-html .about-highlight-item { display: flex; gap: 0.7rem; align-items: flex-start; }
.about-page-html .about-highlight-item .about-highlight-icon {
    width: 38px; height: 38px; border-radius: var(--radius-sm);
    display: flex; align-items: center; justify-content: center; flex-shrink: 0; font-size: 1rem;
}
.about-page-html .about-highlight-item .icon-teal { background: var(--color-primary-light); }
.about-page-html .about-highlight-item .icon-amber { background: var(--color-secondary-light); }
.about-page-html .about-highlight-item .icon-coral { background: var(--color-accent-light); }
.about-page-html .about-highlight-item h4 { font-size: 0.88rem; margin-bottom: 0.1rem; }
.about-page-html .about-highlight-item p { font-size: 0.78rem; color: var(--color-text-light); margin: 0; }

/* ==================== WHAT WE DO ==================== */
.about-page-html .about-whatwedo { background: var(--color-bg); }
.about-page-html .about-whatwedo-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.5rem; }
.about-page-html .about-wwd-card {
    background: var(--color-white); border-radius: var(--radius-lg); padding: 2rem 1.5rem;
    border: 1px solid var(--color-border); text-align: center;
    transition: all 0.4s var(--ease-out); position: relative; overflow: hidden;
}
.about-page-html .about-wwd-card:hover { transform: translateY(-5px); box-shadow: var(--shadow-lg); border-color: var(--color-primary); }
.about-page-html .about-wwd-card::after {
    content: ""; position: absolute; bottom: 0; left: 0; right: 0; height: 3px;
    background: linear-gradient(90deg, var(--color-primary), var(--color-secondary));
    transform: scaleX(0); transition: transform 0.4s var(--ease-out);
}
.about-page-html .about-wwd-card:hover::after { transform: scaleX(1); }
.about-page-html .about-wwd-num { font-family: var(--font-display); font-size: 2.5rem; font-weight: 800; color: var(--color-primary); opacity: 0.25; line-height: 1; margin-bottom: 0.8rem; }
.about-page-html .about-wwd-card h3 { font-size: 1.05rem; margin-bottom: 0.5rem; }
.about-page-html .about-wwd-card p { font-size: 0.87rem; color: var(--color-text-light); line-height: 1.7; margin: 0; }

/* ==================== IMPACT BAR ==================== */
.about-page-html .about-impact-bar {
    display: flex; align-items: center; justify-content: center; gap: 2rem; flex-wrap: wrap;
    background: linear-gradient(135deg, var(--color-dark) 0%, var(--color-dark-soft) 100%);
    border-radius: var(--radius-xl); padding: 2rem 3rem; margin-top: 3rem;
}
.about-page-html .about-impact-stat { text-align: center; }
.about-page-html .about-impact-big {
    font-family: var(--font-display); font-size: 1.9rem; font-weight: 800; color: var(--color-white);
    display: block; line-height: 1; margin-bottom: 0.3rem;
    text-shadow: 0 0 20px rgba(11,138,141,0.4);
}
.about-page-html .about-impact-label { font-size: 0.75rem; color: rgba(255,255,255,0.75); font-weight: 600; letter-spacing: 0.05em; }
.about-page-html .about-impact-divider { width: 1px; height: 40px; background: rgba(255,255,255,0.25); }

/* ==================== MISSION & VISION ==================== */
.about-page-html .about-mission { background: linear-gradient(160deg, var(--color-bg-teal) 0%, var(--color-bg-warm) 100%); }
.about-page-html .about-mission-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; }
.about-page-html .about-mv-card {
    border-radius: var(--radius-xl); overflow: hidden; background: var(--color-white);
    box-shadow: var(--shadow-sm); border: 1px solid var(--color-border);
    padding: 2.5rem; position: relative; transition: all 0.4s var(--ease-out);
}
.about-page-html .about-mv-card:hover { transform: translateY(-4px); box-shadow: var(--shadow-lg); }
.about-page-html .about-mv-card::before { content: ""; position: absolute; top: 0; left: 0; right: 0; height: 4px; }
.about-page-html .about-mv-card.mv-mission::before { background: linear-gradient(90deg, var(--color-primary), var(--color-secondary)); }
.about-page-html .about-mv-card.mv-vision::before { background: linear-gradient(90deg, var(--color-secondary), var(--color-accent)); }
.about-page-html .about-mv-icon-wrap { margin-bottom: 1rem; }
.about-page-html .about-mv-card .about-mv-icon {
    width: 52px; height: 52px; border-radius: var(--radius-md);
    display: flex; align-items: center; justify-content: center; font-size: 1.4rem;
}
.about-page-html .mv-mission .about-mv-icon { background: var(--color-primary-light); }
.about-page-html .mv-vision .about-mv-icon { background: var(--color-secondary-light); }
.about-page-html .about-mv-tag {
    display: inline-block; font-family: var(--font-display); font-size: 0.68rem; font-weight: 700;
    text-transform: uppercase; letter-spacing: 0.12em; padding: 0.2rem 0.7rem;
    border-radius: var(--radius-full); margin-bottom: 0.8rem;
}
.about-page-html .mv-mission .about-mv-tag { background: var(--color-primary-light); color: var(--color-primary); }
.about-page-html .mv-vision .about-mv-tag { background: var(--color-secondary-light); color: var(--color-secondary-dark); }
.about-page-html .about-mv-card h3 { font-size: 1.3rem; margin-bottom: 0.75rem; }
.about-page-html .about-mv-card p { font-size: 0.95rem; color: var(--color-text-light); line-height: 1.85; margin-bottom: 1.2rem; }
.about-page-html .about-mv-quote {
    background: var(--color-bg); border-radius: var(--radius-md); padding: 1rem 1.2rem;
    font-family: var(--font-display); font-size: 0.92rem; font-weight: 600;
    color: var(--color-dark); line-height: 1.5; position: relative;
    border-left: 3px solid var(--color-primary);
}
.about-page-html .mv-vision .about-mv-quote { border-left-color: var(--color-secondary); }
.about-page-html .about-mv-quote-mark { font-size: 2rem; color: var(--color-primary); line-height: 0.5; margin-right: 0.3rem; vertical-align: -0.2em; }
.about-page-html .mv-vision .about-mv-quote-mark { color: var(--color-secondary); }

/* ==================== CTA BANNER ==================== */
.about-page-html .cta-banner {
    background: linear-gradient(135deg, var(--color-primary) 0%, var(--color-primary-dark) 100%);
    border-radius: var(--radius-xl); padding: 3rem 2.5rem; text-align: center;
    color: var(--color-white); position: relative; overflow: hidden; margin: 0 1.5rem;
}
.about-page-html .cta-banner::before {
    content: ""; position: absolute; top: -40%; right: -15%; width: 350px; height: 350px;
    background: radial-gradient(circle, rgba(255,255,255,0.1) 0%, transparent 70%);
    border-radius: 50%; pointer-events: none;
}
.about-page-html .cta-banner h2 { font-size: clamp(1.4rem,2.5vw,2rem); color: var(--color-white); margin-bottom: 0.6rem; }
.about-page-html .cta-banner p { opacity: 0.85; margin-bottom: 1.5rem; max-width: 480px; margin-left: auto; margin-right: auto; }
.about-page-html .cta-banner .button-accent { border: 2px solid rgba(255,255,255,0.2); }

/* ==================== FADE-IN ANIMATION ==================== */
.about-page-html .fade-in { opacity: 0; transform: translateY(25px); transition: opacity 0.6s var(--ease-out), transform 0.6s var(--ease-out); }
.about-page-html .fade-in.visible { opacity: 1; transform: translateY(0); }
.about-page-html .fd1 { transition-delay: 0.1s; }
.about-page-html .fd2 { transition-delay: 0.2s; }

/* ==================== RESPONSIVE ==================== */
@media (max-width: 1024px) {
    .about-page-html .about-who-grid { grid-template-columns: 1fr; gap: 2.5rem; }
    .about-page-html .about-who-image { max-width: 480px; margin: 0 auto; }
    .about-page-html .about-whatwedo-grid { grid-template-columns: repeat(2, 1fr); }
    .about-page-html .about-mission-grid { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 768px) {
    .about-page-html .about-hero { padding: 7rem 0 3.5rem; }
    .about-page-html .about-mission-grid { grid-template-columns: 1fr; }
    .about-page-html .about-whatwedo-grid { grid-template-columns: 1fr; }
    .about-page-html .about-impact-bar { padding: 1.5rem; gap: 1.2rem; display: grid; grid-template-columns: 1fr 1fr; }
    .about-page-html .about-impact-divider { display: none; }
    .about-page-html .about-highlights { grid-template-columns: 1fr; }
}
@media (max-width: 480px) {
    .about-page-html .about-impact-bar { grid-template-columns: 1fr 1fr; }
}
@media (prefers-reduced-motion: reduce) {
    .about-page-html .fade-in { opacity: 1; transform: none; transition: none; }
    .about-page-html .about-hero-inner { animation: none; }
}
</style>

<div class="about-page-html">

<!-- ==================== ABOUT HERO ==================== -->
<section class="about-hero">
    <div class="about-hero-bg"></div>
    <div class="container">
        <div class="about-hero-inner">
            <span class="eyebrow">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1 0-5H20"/></svg>
                About Us
            </span>
            <h1 class="about-hero-title">
                Transforming Education<br>
                <span class="highlight">Across Karnataka</span>
            </h1>
            <p class="about-hero-lead">
                Established in 2021, Sankalp Learning empowers government school students to achieve their dreams.
            </p>
        </div>
    </div>
    <div class="about-hero-shape"></div>
</section>


<!-- ==================== WHO WE ARE ==================== -->
<section class="about-who section">
    <div class="container">
        <div class="about-who-grid">
            <div class="about-who-image fade-in">
                <!-- VISUAL CARD (shown when no feature image is set) -->
                <div class="about-who-visual-card">
                    <div class="about-vc-header">
                        <div class="about-vc-logo">S</div>
                        <div>
                            <div class="about-vc-brand">Sankalp Learning</div>
                            <div class="about-vc-sub">Est. 2021 &middot; Karnataka, India</div>
                        </div>
                    </div>
                    <div class="about-vc-grid">
